from flask import Flask, redirect, request, session
from flask_oidc import OpenIDConnect
from flask_pymongo import PyMongo

app = Flask(__name__)
app.secret_key = b'secret'
mongo = PyMongo(app)

oidc = OpenIDConnect(
    client_id='your_client_id',
    client_secret='your_client_secret',
    api_base_url='your_api_base_url',
    access_token_url='your_access_token_url',
    authorize_url='your_authorize_url',
    client_kwargs={'scope': 'openid profile email'},
)

@app.route('/')
def home():
    if oidc.is_logged_in:
        return f'Welcome, {oidc.user_info["name"]}!'
    else:
        return redirect(oidc.login_url)

@app.route('/callback')
@oidc.authorized_handler
def callback():
    token = oidc.get_access_token()
    id_token = oidc.get_id_token()
    claims = oidc.decode_id_token(id_token)

    session['user_id'] = claims['sub']
    session['email'] = claims['email']

    return redirect('/')

if __name__ == '__main__':
    app.run()